  ('social-worker-moex-06487', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Roberts（2006）提出三個 ABCD 模式（Triple ABCD model）的危機管理與災難情境。下列那一個不是 Roberts所指的災難管理階段？', '["危機介入", "災難救援人員抵達", "建立救援系統", "延長復原"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "a3d845e75c7c", "answer_pdf_sha1": "ca9f253103ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06488', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何種事件或運動為美國社會工作專業發展之重要歷史：①濟貧法（Poor Law）之制定  ②慈善組織會', '["睦鄰公社（Settlement House）", "漢堡制與愛爾伯福制", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "a3d845e75c7c", "answer_pdf_sha1": "ca9f253103ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
